1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Scenario = {
3	  customer?: { yearsWithMHPCO?: number };
4	  steps: Array<{ op: string; items?: Item[] }>;
5	};
6	
7	const PROCESSING_FEE = 5;
8	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	const BLOCK_OF_3_PRICE = 60;
17	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	
24	function quotePremium(items: Item[], yearsWithMHPCO: number): number {
25	  const countsByType: Record<string, number> = {};
26	  for (const item of items) {
27	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
28	  }
29	  let policyBase = 0;
30	  for (const [type, count] of Object.entries(countsByType)) {
31	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
32	      policyBase += BLOCK_OF_3_PRICE;
33	    } else {
34	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
35	    }
36	  }
37	  let itemSurcharges = 0;
38	  for (const item of items) {
39	    let rate = 0;
40	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
41	      rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
42	    }
43	    if (item.cursed) {
44	      rate += CURSE_SURCHARGE_RATE;
45	    }
46	    itemSurcharges += rate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
47	  }
48	  const firstInsurance = policyBase / 10;
49	  const loyaltyDiscount =
50	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
51	  return (
52	    Math.ceil(policyBase + itemSurcharges + firstInsurance - loyaltyDiscount) +
53	    PROCESSING_FEE
54	  );
55	}
56	
57	export function processScenario(scenario: unknown): unknown {
58	  const { customer, steps } = scenario as Scenario;
59	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
60	  const results = steps.map((step) => ({
61	    premium: quotePremium(step.items ?? [], yearsWithMHPCO),
62	  }));
63	  return { results };
64	}
